"use client";

import React, { useState } from 'react';
import Image from 'next/image';
import { ShoppingCart, Save, Trash2, Edit2, X, Camera } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent } from "@/components/ui/card";
import { cn } from '@/lib/utils';

export interface MakeupService {
  id: string;
  name: string;
  price: number;
  description: string;
  imageUrl: string;
}

interface ServiceCardProps {
  service: MakeupService;
  isSupervisor: boolean;
  onUpdate: (service: MakeupService) => void;
  onDelete: (id: string) => void;
}

export function ServiceCard({ service, isSupervisor, onUpdate, onDelete }: ServiceCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedService, setEditedService] = useState(service);

  const handleWhatsApp = () => {
    const phone = "961xxxxxxxx"; // Replace with your real WhatsApp number
    const message = `مرحباً Girls Store، أود طلب: ${service.name}\nالسعر: ${service.price}$\nطريقة الدفع: Whish Money`;
    window.open(`https://wa.me/${phone}?text=${encodeURIComponent(message)}`, '_blank');
  };

  const handleSave = () => {
    onUpdate(editedService);
    setIsEditing(false);
  };

  return (
    <Card className="group overflow-hidden border border-muted shadow-lg hover:shadow-2xl transition-all duration-500 bg-white rounded-[2rem]">
      <div className="relative h-72 w-full overflow-hidden bg-muted">
        <Image
          src={service.imageUrl}
          alt={service.name}
          fill
          className="object-cover transition-transform duration-700 group-hover:scale-110"
          data-ai-hint="beauty product"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
        
        {isSupervisor && (
          <div className="absolute top-4 right-4 flex gap-2">
            <Button 
              size="icon" 
              variant="secondary" 
              className="rounded-full shadow-md bg-white/90 hover:bg-primary hover:text-white"
              onClick={() => setIsEditing(!isEditing)}
            >
              {isEditing ? <X className="w-4 h-4" /> : <Edit2 className="w-4 h-4" />}
            </Button>
            <Button 
              size="icon" 
              variant="destructive" 
              className="rounded-full shadow-md"
              onClick={() => onDelete(service.id)}
            >
              <Trash2 className="w-4 h-4" />
            </Button>
          </div>
        )}
      </div>

      <CardContent className="p-8 text-center">
        {isEditing ? (
          <div className="space-y-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold uppercase tracking-widest text-primary">Name</label>
              <Input 
                className="text-center rounded-xl"
                value={editedService.name} 
                onChange={(e) => setEditedService({...editedService, name: e.target.value})} 
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold uppercase tracking-widest text-primary">Price ($)</label>
              <Input 
                className="text-center rounded-xl"
                type="number"
                value={editedService.price} 
                onChange={(e) => setEditedService({...editedService, price: Number(e.target.value)})} 
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold uppercase tracking-widest text-primary">Description</label>
              <Textarea 
                className="text-center rounded-xl"
                value={editedService.description} 
                onChange={(e) => setEditedService({...editedService, description: e.target.value})} 
                rows={3}
              />
            </div>
            <Button onClick={handleSave} className="w-full gap-2 rounded-xl bg-green-500 hover:bg-green-600 text-white">
              <Save className="w-4 h-4" /> Save Changes
            </Button>
          </div>
        ) : (
          <div className="flex flex-col h-full">
            <h3 className="text-2xl font-headline text-foreground mb-1 leading-tight">{service.name}</h3>
            <p className="text-xl font-bold text-primary mb-3">${service.price}</p>
            <p className="text-muted-foreground text-sm leading-relaxed mb-8 flex-grow line-clamp-3 px-2">
              {service.description}
            </p>
            <Button 
              onClick={handleWhatsApp}
              className="w-full py-6 text-lg rounded-2xl bg-primary hover:bg-primary/90 transition-all duration-300 shadow-md shadow-primary/20 gap-3 group/btn"
            >
              <ShoppingCart className="w-5 h-5 group-hover/btn:scale-110 transition-transform" />
              <span className="font-bold tracking-wide">Order on WOS</span>
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
}