"use client";

import React, { useState, useEffect } from 'react';
import { Plus, Sparkles } from 'lucide-react';
import { Button } from "@/components/ui/button";
import { ServiceCard, MakeupService } from '@/components/ServiceCard';
import { AIGeneratorDialog } from '@/components/AIGeneratorDialog';
import { useToast } from "@/hooks/use-toast";
import { PlaceHolderImages } from '@/lib/placeholder-images';

export default function GirlsStore() {
  const { toast } = useToast();
  const [isSupervisor, setIsSupervisor] = useState(false);
  const [clickCount, setClickCount] = useState(0);
  
  const [services, setServices] = useState<MakeupService[]>(() => [
    { 
      id: '1', 
      name: "Premium Foundation", 
      price: 35, 
      description: "Full coverage for a flawless skin look. Designed for all-day wear with a natural finish.", 
      imageUrl: "https://images.unsplash.com/photo-1596462502278-27bf87582175?q=80&w=500"
    },
    { 
      id: '2', 
      name: "Signature Palette", 
      price: 45, 
      description: "High pigmentation golden hour shades. Includes 12 versatile colors for any occasion.", 
      imageUrl: "https://images.unsplash.com/photo-1512496011212-323a784629c2?q=80&w=500"
    },
    { 
      id: '3', 
      name: "Bridal Makeup", 
      price: 150, 
      description: "Professional wedding look with premium lashes. Includes a consultation and long-lasting finish.", 
      imageUrl: "https://images.unsplash.com/photo-1487412720507-e7ab37603c6f?q=80&w=500"
    }
  ]);

  const handleAdminTrigger = () => {
    setClickCount(prev => prev + 1);
  };

  useEffect(() => {
    if (clickCount === 7) {
      const newState = !isSupervisor;
      setIsSupervisor(newState);
      setClickCount(0);
      toast({
        title: newState ? "Supervisor Mode Enabled" : "Supervisor Mode Disabled",
        description: newState ? "Welcome back, Manager. You can now manage Girls Store." : "Returned to Customer View.",
      });
    }
  }, [clickCount, isSupervisor, toast]);

  const addService = (name: string, description: string) => {
    const newService: MakeupService = {
      id: Date.now().toString(),
      name,
      price: 100,
      description,
      imageUrl: `https://picsum.photos/seed/${Date.now()}/800/600`
    };
    setServices([newService, ...services]);
  };

  const updateService = (updated: MakeupService) => {
    setServices(services.map(s => s.id === updated.id ? updated : s));
  };

  const deleteService = (id: string) => {
    setServices(services.filter(s => s.id !== id));
  };

  return (
    <div className="min-h-screen bg-background flex flex-col font-body">
      {/* --- Header Section --- */}
      <header className="sticky top-0 z-40 w-full bg-white/90 backdrop-blur-md border-b border-secondary">
        <div className="max-w-7xl mx-auto px-6 py-6 flex flex-col items-center">
          <span className="text-[10px] tracking-[0.3em] text-primary font-bold uppercase mb-2">
            Powered by Hassan Deeb
          </span>
          
          <div className="flex items-center gap-4">
            <h1 
              onClick={handleAdminTrigger}
              className="text-4xl md:text-5xl font-headline text-primary cursor-pointer select-none transition-all hover:scale-[1.02] active:scale-95 text-center"
            >
              Girls Store
            </h1>
          </div>
          
          {isSupervisor && (
            <div className="mt-2 bg-primary text-white px-3 py-1 rounded-full text-[10px] uppercase tracking-widest animate-pulse font-bold">
              Supervisor Mode Active
            </div>
          )}
        </div>
      </header>

      {/* --- Main Content --- */}
      <main className="flex-grow max-w-7xl mx-auto px-6 py-12 w-full">
        {isSupervisor && (
          <div className="mb-12 flex flex-col sm:flex-row items-center justify-between gap-6 p-6 bg-white rounded-[2rem] border border-secondary shadow-sm">
            <div>
              <h2 className="text-2xl font-headline mb-1">Inventory Management</h2>
              <p className="text-muted-foreground text-sm">Add or modify Girls Store offerings.</p>
            </div>
            <div className="flex gap-3">
              <AIGeneratorDialog onGenerated={addService} />
              <Button 
                onClick={() => addService("New Product", "Enter description here...")}
                className="gap-2 rounded-xl bg-primary hover:bg-primary/90"
              >
                <Plus className="w-4 h-4" /> Add Manually
              </Button>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
          {services.map(service => (
            <ServiceCard 
              key={service.id} 
              service={service} 
              isSupervisor={isSupervisor}
              onUpdate={updateService}
              onDelete={deleteService}
            />
          ))}

          {isSupervisor && services.length === 0 && (
            <div 
              onClick={() => addService("Untitled Product", "Describe your magic...")}
              className="group border-4 border-dashed border-secondary rounded-[2rem] flex flex-col items-center justify-center p-20 cursor-pointer hover:border-primary/40 transition-all bg-white/50"
            >
              <div className="bg-primary/10 p-6 rounded-full group-hover:scale-110 transition-transform">
                <Plus size={48} className="text-primary/40" />
              </div>
              <span className="text-primary/60 font-bold mt-6 text-xl">Add to Girls Store</span>
            </div>
          )}
        </div>
      </main>

      {/* --- Footer Section --- */}
      <footer className="py-12 border-t border-secondary">
        <div className="max-w-7xl mx-auto px-6 flex flex-col items-center gap-6">
          <div className="inline-block bg-white px-6 py-2 rounded-full border border-secondary shadow-sm">
            <p className="text-[11px] text-foreground tracking-wider uppercase">
              Payment via <span className="text-primary font-bold">Whish Money</span>
            </p>
          </div>
          
          <div className="flex items-center gap-2 text-primary/40">
            <Sparkles className="w-3 h-3" />
            <span className="text-[10px] tracking-tighter uppercase font-bold">Girls Store © 2024</span>
          </div>
        </div>
      </footer>
    </div>
  );
}